UPDATE products p
SET 
  price = CASE WHEN u.price > 0 THEN u.price ELSE p.price END,
  buying_price = CASE WHEN u.buying_price > 0 THEN u.buying_price ELSE p.buying_price END
FROM _price_updates u
WHERE p.name = u.name;

